// SessionServiceHandler is an implementation of the fletcher.v1.SessionService service.
type SessionServiceHandler interface {
	// CreateSession provisions a session's persistent fork and boots its VM. The
	// returned session has state RUNNING.
	CreateSession(context.Context, *connect.Request[v1.CreateSessionRequest]) (*connect.Response[v1.CreateSessionResponse], error)
	// GetSession fetches a session by ID or name.
	GetSession(context.Context, *connect.Request[v1.GetSessionRequest]) (*connect.Response[v1.GetSessionResponse], error)
	// ListSessions returns all sessions, newest first.
	ListSessions(context.Context, *connect.Request[v1.ListSessionsRequest]) (*connect.Response[v1.ListSessionsResponse], error)
	// StartSession boots a stopped session's VM against its persisted fork.
	StartSession(context.Context, *connect.Request[v1.StartSessionRequest]) (*connect.Response[v1.StartSessionResponse], error)
	// StopSession stops a running session's VM, keeping its fork on disk.
	StopSession(context.Context, *connect.Request[v1.StopSessionRequest]) (*connect.Response[v1.StopSessionResponse], error)
	// DeleteSession stops the VM (if running) and destroys the fork.
	DeleteSession(context.Context, *connect.Request[v1.DeleteSessionRequest]) (*connect.Response[v1.DeleteSessionResponse], error)
	// UpdateSession changes a session's egress policy and/or gateway. Both are
	// applied to the fork at VM boot, so a change to a running session takes
	// effect on its next start (restart_required reports that).
	UpdateSession(context.Context, *connect.Request[v1.UpdateSessionRequest]) (*connect.Response[v1.UpdateSessionResponse], error)
	// ExecSession runs a command inside a running session and returns its
	// captured output and exit code.
	ExecSession(context.Context, *connect.Request[v1.ExecSessionRequest]) (*connect.Response[v1.ExecSessionResponse], error)
	// ShellSession opens an interactive PTY in a running session. The first
	// client message must carry a ShellStart; later messages carry stdin bytes
	// or window-resize events. Server messages carry terminal output, then a
	// final exit code when the shell ends. Full-duplex: requires HTTP/2.
	ShellSession(context.Context, *connect.BidiStream[v1.ShellSessionRequest, v1.ShellSessionResponse]) error
	// ProxySession brokers a raw byte stream into a running session VM's SSH
	// server: the daemon relays it over vsock (the VM stays unroutable). It
	// backs `fletcher session ssh` as an SSH ProxyCommand. The first client
	// message must carry a ProxyOpen; all later messages (both directions) are
	// opaque bytes. Full-duplex: requires HTTP/2.
	ProxySession(context.Context, *connect.BidiStream[v1.ProxySessionRequest, v1.ProxySessionResponse]) error
	// PublishPort exposes a port the session serves, brokered by the daemon so
	// the VM stays unroutable. The returned port is reachable over the tunnel at
	// its tunnel_port.
	PublishPort(context.Context, *connect.Request[v1.PublishPortRequest]) (*connect.Response[v1.PublishPortResponse], error)
	// UnpublishPort stops forwarding a session's published port.
	UnpublishPort(context.Context, *connect.Request[v1.UnpublishPortRequest]) (*connect.Response[v1.UnpublishPortResponse], error)
	// ListPorts returns a session's published ports.
	ListPorts(context.Context, *connect.Request[v1.ListPortsRequest]) (*connect.Response[v1.ListPortsResponse], error)
	// RestartSession stops a running session's VM and starts it again against the
	// same fork. For a run_app (deploy) session this re-runs the image's app.
	RestartSession(context.Context, *connect.Request[v1.RestartSessionRequest]) (*connect.Response[v1.RestartSessionResponse], error)
	// RedeploySession replaces a session's disk with a fresh fork of its current
	// template image and restarts it (a clean redeploy, vs RestartSession which
	// keeps the same disk). For a registry-sourced image it first attempts a
	// best-effort re-pull to the latest; a local image is re-forked as-is.
	RedeploySession(context.Context, *connect.Request[v1.RedeploySessionRequest]) (*connect.Response[v1.RedeploySessionResponse], error)
	// GetSessionLogs returns the tail of a run_app session's app log
	// (/var/log/fletcher-app.log), captured from the running VM.
	GetSessionLogs(context.Context, *connect.Request[v1.GetSessionLogsRequest]) (*connect.Response[v1.GetSessionLogsResponse], error)
	// StreamSessionLogs streams a run_app session's app log; with follow set it
	// keeps streaming new lines (like `tail -f`) until the client disconnects.
	// Server-streaming, so it needs HTTP/2 (the same NIOHTTPClient path the shell
	// uses on iOS).
	StreamSessionLogs(context.Context, *connect.Request[v1.StreamSessionLogsRequest], *connect.ServerStream[v1.StreamSessionLogsResponse]) error
	// CommitSessionImage commits a session's fork as a new image template (the
	// docker-commit analogue), so jobs, sessions, and deploys can boot from it.
	// A running session's disk is synced first; the result is at worst
	// crash-consistent. Requires a snapshot driver that can commit (ext4).
	CommitSessionImage(context.Context, *connect.Request[v1.CommitSessionImageRequest]) (*connect.Response[v1.CommitSessionImageResponse], error)
	// RollbackSession swaps a session back to the fork its last redeploy
	// retired and restarts it - the one-step undo for a bad redeploy. Rolling
	// forward again is the same call (the forks swap each time).
	RollbackSession(context.Context, *connect.Request[v1.RollbackSessionRequest]) (*connect.Response[v1.RollbackSessionResponse], error)
	// UploadFile streams a file from the client into a running session's fork. The
	// first client message must carry an UploadStart (ref + path + mode); later
	// messages carry chunk bytes. The daemon relays them over vsock to the guest,
	// which writes the file atomically and chowns it to the login user. The VM
	// stays unroutable - the bytes ride the daemon control channel, not a route
	// into the VM. Client-streaming: requires HTTP/2.
	UploadFile(context.Context, *connect.ClientStream[v1.UploadFileRequest]) (*connect.Response[v1.UploadFileResponse], error)
	// DownloadFile streams a file out of a running session's fork to the client.
	// The first response message carries a FileInfo (size + mode); later messages
	// carry chunk bytes. Server-streaming: requires HTTP/2.
	DownloadFile(context.Context, *connect.Request[v1.DownloadFileRequest], *connect.ServerStream[v1.DownloadFileResponse]) error
	// ListDir lists a directory inside a running session's fork. Served by the
	// guest init in pure Go (no shell), so it works on any image - including a
	// distroless one with no /bin/sh, where exec/shell are unavailable.
	ListDir(context.Context, *connect.Request[v1.ListDirRequest]) (*connect.Response[v1.ListDirResponse], error)
	// FileOp performs a delete, move (rename), or copy inside a running session's
	// fork. Like the other file RPCs it is served by the guest init in pure Go, so
	// it works on a shell-less image.
	FileOp(context.Context, *connect.Request[v1.FileOpRequest]) (*connect.Response[v1.FileOpResponse], error)
}

